        // Read ELF header
        const entryPoint = elfView.getUint32(24, true); // little endian
        const phoff = elfView.getUint32(28, true);
        const phnum = elfView.getUint16(44, true);

        console.log(`ELF entry point: 0x${entryPoint.toString(16)}`);

        // Load program headers
        for (let i = 0; i < phnum; i++) {
            const phOffset = phoff + (i * 32);
            const type = elfView.getUint32(phOffset, true);

            if (type === 1) { // PT_LOAD
                const offset = elfView.getUint32(phOffset + 4, true);
                const vaddr = elfView.getUint32(phOffset + 8, true);
                const filesz = elfView.getUint32(phOffset + 16, true);
                const memsz = elfView.getUint32(phOffset + 20, true);
                const flags = elfView.getUint32(phOffset + 24, true);

                console.log(`Loading segment: vaddr=0x${vaddr.toString(16)}, filesz=${filesz}, memsz=${memsz}, flags=${flags}`);

                // Copy file data to memory
                const segmentData = elfData.slice(offset, offset + filesz);
                this.memoryU8.set(segmentData, vaddr);

                // Zero out BSS if memsz > filesz
                if (memsz > filesz) {
                    this.memoryU8.fill(0, vaddr + filesz, vaddr + memsz);
                }
            }
        }

        this.pc = entryPoint;
        return entryPoint;
    }
