    // Read memory helpers
    readU32(addr) {
        return this.memoryView.getUint32(addr, true); // little endian
    }

    writeU32(addr, value) {
        this.memoryView.setUint32(addr, value, true);
    }

    readU16(addr) {
        return this.memoryView.getUint16(addr, true);
    }

    writeU16(addr, value) {
        this.memoryView.setUint16(addr, value, true);
    }

    readU8(addr) {
        return this.memoryView.getUint8(addr);
    }

    writeU8(addr, value) {
        this.memoryView.setUint8(addr, value);
    }

    // Sign extend helpers
    signExtend16(value) {
        return (value << 16) >> 16;
    }

    signExtend8(value) {
        return (value << 24) >> 24;
    }

    // MIPS instruction execution
    executeInstruction() {
        const instruction = this.readU32(this.pc);
        const opcode = (instruction >>> 26) & 0x3F;
        const rs = (instruction >>> 21) & 0x1F;
        const rt = (instruction >>> 16) & 0x1F;
        const rd = (instruction >>> 11) & 0x1F;
        const shamt = (instruction >>> 6) & 0x1F;
        const funct = instruction & 0x3F;
        const immediate = this.signExtend16(instruction & 0xFFFF);
        const address = instruction & 0x3FFFFFF;

        this.pc += 4;

        switch (opcode) {
            case 0x00: // Special
                this.executeSpecial(rs, rt, rd, shamt, funct);
                break;
            case 0x02: // J - Jump
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x03: // JAL - Jump and Link
                this.registers[31] = this.pc;
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x04: // BEQ - Branch if Equal
                if (this.registers[rs] === this.registers[rt]) {
                    this.pc += immediate << 2;
