  "commands": [
    {
      "keystrokes": "cat >> vm.js << 'EOF'

    // Platform interface functions for doomgeneric
    setupPlatformFunctions() {
        // Allocate memory for screen buffer (640x400x4 bytes)
        const screenBufferAddr = 0x10000000; // Use high memory address
        this.screenBuffer = screenBufferAddr;

        // Set up function pointers in memory (these would be resolved by the linker)
        // For now, we'll handle them through special addresses in memory access
    }

    // BMP file writing (similar to the C version)
    writeBMPFile(filename, buffer, width, height) {
        const imageSize = width * height * 4;
        const fileSize = 54 + imageSize;

        const bmp = new Uint8Array(fileSize);
        const view = new DataView(bmp.buffer);

        // BMP Header
        view.setUint16(0, 0x4D42, true); // 'BM'
        view.setUint32(2, fileSize, true); // File size
        view.setUint32(6, 0, true); // Reserved
        view.setUint32(10, 54, true); // Offset to pixel data

        // DIB Header
        view.setUint32(14, 40, true); // DIB header size
        view.setUint32(18, width, true); // Width
        view.setInt32(22, -height, true); // Height (negative for top-down)
        view.setUint16(26, 1, true); // Color planes
        view.setUint16(28, 32, true); // Bits per pixel
        view.setUint32(30, 0, true); // Compression
        view.setUint32(34, imageSize, true); // Image size
        view.setUint32(38, 0, true); // X pixels per meter
        view.setUint32(42, 0, true); // Y pixels per meter
        view.setUint32(46, 0, true); // Colors used
        view.setUint32(50, 0, true); // Important colors

        // Copy pixel data
        for (let i = 0; i < imageSize; i += 4) {
            const pixel = this.readU32(buffer + i);
            view.setUint32(54 + i, pixel, true);
        }

        // Write to real filesystem
        try {
            fs.writeFileSync(filename, bmp);
        } catch (e) {
            console.error('Failed to write BMP:', e.message);
        }
    }

    // Handle special memory accesses for platform functions
    handleSpecialAccess(addr, isWrite, value) {
        // DG_ScreenBuffer access
        if (addr >= this.screenBuffer && addr < this.screenBuffer + (640 * 400 * 4)) {
            if (isWrite) {
                this.writeU32(addr, value);
            } else {
                return this.readU32(addr);
            }
        }

        // Handle function calls through special addresses
        switch (addr) {
            case 0xDEADBEEF: // DG_DrawFrame
                if (this.frameCounter % 10 === 0) {
                    this.writeBMPFile('/tmp/frame.bmp', this.screenBuffer, 640, 400);
                    console.log(`Frame ${Math.floor(this.frameCounter / 10)} saved`);
                }
                this.frameCounter++;
                return 0;

            case 0xDEADBEF0: // DG_GetTicksMs
                return this.frameCounter; // Simple tick counter

            case 0xDEADBEF1: // DG_SleepMs
                // No-op for now
                return 0;

            case 0xDEADBEF2: // DG_GetKey
                return 0; // No input for now
        }

        return 0;
    }

    // Main execution loop
    run() {
        this.setupPlatformFunctions();

        let instructionCount = 0;
        const maxInstructions = 100000000; // Safety limit

        try {
            while (instructionCount < maxInstructions) {
                // Check for special function calls
                const instruction = this.readU32(this.pc);

                this.executeInstruction();
                instructionCount++;

                if (instructionCount % 1000000 === 0) {
                    console.log(`Executed ${instructionCount} instructions, PC: 0x${this.pc.toString(16)}`);
                }

                // Break on infinite loop detection
                if (this.pc === 0) {
                    console.log('Program ended (PC = 0)');
                    break;
                }
            }
        } catch (error) {
            console.error(`Execution error at PC 0x${this.pc.toString(16)}:`, error.message);
            console.error(`Instruction count: ${instructionCount}`);
            throw error;
        }

        console.log(`Execution completed. Total instructions: ${instructionCount}`);
    }
}

// Main entry point
function main() {
    console.log('MIPS VM starting...');

    const vm = new MipsVM();

    try {
        vm.loadELF('doomgeneric_mips');
        console.log('ELF loaded successfully');

        // Set up stack pointer (use high memory)
        vm.registers[29] = 0x7FFF0000; // $sp

        console.log('Starting execution...');
        vm.run();

    } catch (error) {
        console.error('VM Error:', error.message);
        process.exit(1);
    }
}

if (require.main === module) {
    main();
}
EOF
