    // Sign extend helpers
    signExtend16(value) {
        return (value << 16) >> 16;
    }

    signExtend8(value) {
        return (value << 24) >> 24;
    }

    // MIPS instruction execution
    executeInstruction() {
        const instruction = this.readU32(this.pc);
        const opcode = (instruction >>> 26) & 0x3F;
        const rs = (instruction >>> 21) & 0x1F;
        const rt = (instruction >>> 16) & 0x1F;
        const rd = (instruction >>> 11) & 0x1F;
        const shamt = (instruction >>> 6) & 0x1F;
        const funct = instruction & 0x3F;
        const immediate = this.signExtend16(instruction & 0xFFFF);
        const address = instruction & 0x3FFFFFF;

        this.pc += 4;

        switch (opcode) {
            case 0x00: // Special
                this.executeSpecial(rs, rt, rd, shamt, funct);
                break;
            case 0x02: // J - Jump
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x03: // JAL - Jump and Link
                this.registers[31] = this.pc;
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x04: // BEQ - Branch if Equal
                if (this.registers[rs] === this.registers[rt]) {
                    this.pc += immediate << 2;
                }
                break;
            case 0x05: // BNE - Branch if Not Equal
                if (this.registers[rs] !== this.registers[rt]) {
                    this.pc += immediate << 2;
                }
                break;
            case 0x08: // ADDI - Add Immediate
                this.registers[rt] = (this.registers[rs] + immediate) >>> 0;
                break;
            case 0x09: // ADDIU - Add Immediate Unsigned
                this.registers[rt] = (this.registers[rs] + immediate) >>> 0;
                break;
            case 0x0C: // ANDI - AND Immediate
                this.registers[rt] = this.registers[rs] & (immediate & 0xFFFF);
                break;
            case 0x0D: // ORI - OR Immediate
                this.registers[rt] = this.registers[rs] | (immediate & 0xFFFF);
                break;
            case 0x0F: // LUI - Load Upper Immediate
                this.registers[rt] = (immediate << 16) >>> 0;
                break;
            case 0x23: // LW - Load Word
                this.registers[rt] = this.readU32(this.registers[rs] + immediate);
                break;
            case 0x2B: // SW - Store Word
                this.writeU32(this.registers[rs] + immediate, this.registers[rt]);
                break;
            default:
                console.log(`Unknown opcode: 0x${opcode.toString(16)} at PC 0x${(this.pc - 4).toString(16)}`);
                break;
        }

        this.registers[0] = 0;
    }
