                break;
            case 0x20: // ADD
                this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
                break;
            case 0x21: // ADDU
                this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
                break;
            case 0x24: // AND
                this.registers[rd] = this.registers[rs] & this.registers[rt];
                break;
            case 0x25: // OR
                this.registers[rd] = this.registers[rs] | this.registers[rt];
                break;
            default:
                console.log(`Unknown special function: 0x${funct.toString(16)} at PC 0x${(this.pc - 4).toString(16)}`);
                break;
        }
    }

    // Simple system call handling
    handleSyscall() {
        const syscallNum = this.registers[2]; // v0 register
        console.log(`Syscall ${syscallNum} called`);
        this.registers[2] = 0; // Return success for now
    }

    // Helper to read string from memory
    readString(addr) {
        let str = '';
        let i = 0;
        while (true) {
            const byte = this.readU8(addr + i);
            if (byte === 0) break;
            str += String.fromCharCode(byte);
            i++;
            if (i > 1000) break; // Safety limit
        }
        return str;
