    // Main execution loop
    run() {
        let instructionCount = 0;
        const maxInstructions = 1000000; // Lower limit for testing

        try {
            while (instructionCount < maxInstructions) {
                this.executeInstruction();
                instructionCount++;

                if (instructionCount % 100000 === 0) {
