    loadELF(filename) {
        const elfData = fs.readFileSync(filename);
        const elfView = new DataView(elfData.buffer.slice(elfData.byteOffset, elfData.byteOffset + elfData.byteLength));

        if (elfView.getUint32(0, false) !== 0x7F454C46) {
            throw new Error('Invalid ELF magic');
        }

        const entryPoint = elfView.getUint32(24, true);
        const phoff = elfView.getUint32(28, true);
        const phnum = elfView.getUint16(44, true);

        console.log(`ELF entry point: 0x${entryPoint.toString(16)}`);

        let physicalOffset = 0;

        for (let i = 0; i < phnum; i++) {
            const phOffset = phoff + (i * 32);
            const type = elfView.getUint32(phOffset, true);

            if (type === 1) { // PT_LOAD
                const offset = elfView.getUint32(phOffset + 4, true);
                const vaddr = elfView.getUint32(phOffset + 8, true);
                const filesz = elfView.getUint32(phOffset + 16, true);
                const memsz = elfView.getUint32(phOffset + 20, true);
                const flags = elfView.getUint32(phOffset + 24, true);

                console.log(`Loading segment: vaddr=0x${vaddr.toString(16)}, filesz=${filesz}, memsz=${memsz}`);

                this.addMemoryRegion(vaddr, memsz, physicalOffset);

                const segmentData = elfData.slice(offset, offset + filesz);
                this.memoryU8.set(segmentData, physicalOffset);

                if (memsz > filesz) {
                    this.memoryU8.fill(0, physicalOffset + filesz, physicalOffset + memsz);
                }

                physicalOffset += memsz;
                physicalOffset = (physicalOffset + 4095) & ~4095;
            }
        }

        // Add stack
        const stackSize = 1024 * 1024;
        const stackVaddr = 0x7FFF0000;
        this.addMemoryRegion(stackVaddr - stackSize, stackSize, physicalOffset);

        this.pc = entryPoint;
        return entryPoint;
    }

    readU32(addr) {
        const physAddr = this.virtualToPhysical(addr);
        return this.memoryView.getUint32(physAddr, true);
    }

    writeU32(addr, value) {
        const physAddr = this.virtualToPhysical(addr);
        this.memoryView.setUint32(physAddr, value, true);
    }

    readU8(addr) {
        const physAddr = this.virtualToPhysical(addr);
        return this.memoryView.getUint8(physAddr);
    }

    writeU8(addr, value) {
        const physAddr = this.virtualToPhysical(addr);
        this.memoryView.setUint8(physAddr, value);
    }
