    signExtend16(value) {
        return (value << 16) >> 16;
    }

    executeInstruction() {
        const instruction = this.readU32(this.pc);
        const opcode = (instruction >>> 26) & 0x3F;
        const rs = (instruction >>> 21) & 0x1F;
        const rt = (instruction >>> 16) & 0x1F;
        const rd = (instruction >>> 11) & 0x1F;
        const funct = instruction & 0x3F;
        const immediate = this.signExtend16(instruction & 0xFFFF);
        const address = instruction & 0x3FFFFFF;

        this.pc += 4;

        switch (opcode) {
            case 0x00: // Special
                switch (funct) {
                    case 0x08: // JR
                        this.pc = this.registers[rs];
                        break;
                    case 0x0C: // SYSCALL
                        console.log(`Syscall called at PC 0x${(this.pc-4).toString(16)}`);
                        this.registers[2] = 0; // Return success
                        break;
                    case 0x20: // ADD
                        this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
                        break;
                    case 0x21: // ADDU
                        this.registers[rd] = (this.registers[rs] + this.registers[rt]) >>> 0;
                        break;
                    case 0x25: // OR
                        this.registers[rd] = this.registers[rs] | this.registers[rt];
                        break;
                    default:
                        console.log(`Unknown special: 0x${funct.toString(16)}`);
                        break;
                }
                break;
            case 0x02: // J
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x03: // JAL
                this.registers[31] = this.pc;
                this.pc = (this.pc & 0xF0000000) | (address << 2);
                break;
            case 0x04: // BEQ
                if (this.registers[rs] === this.registers[rt]) {
                    this.pc += immediate << 2;
                }
                break;
            case 0x05: // BNE
                if (this.registers[rs] !== this.registers[rt]) {
                    this.pc += immediate << 2;
                }
                break;
            case 0x08: // ADDI
                this.registers[rt] = (this.registers[rs] + immediate) >>> 0;
                break;
            case 0x09: // ADDIU
                this.registers[rt] = (this.registers[rs] + immediate) >>> 0;
                break;
            case 0x0F: // LUI
                this.registers[rt] = (immediate << 16) >>> 0;
                break;
            case 0x23: // LW
                this.registers[rt] = this.readU32(this.registers[rs] + immediate);
                break;
            case 0x2B: // SW
                this.writeU32(this.registers[rs] + immediate, this.registers[rt]);
                break;
            default:
                console.log(`Unknown opcode: 0x${opcode.toString(16)} at PC 0x${(this.pc-4).toString(16)}`);
                break;
        }

        this.registers[0] = 0; // $zero is always 0
    }

    run() {
        let instructionCount = 0;
        const maxInstructions = 1000000;

        try {
            while (instructionCount < maxInstructions) {
                this.executeInstruction();
                instructionCount++;

                if (instructionCount % 100000 === 0) {
                    console.log(`Executed ${instructionCount} instructions, PC: 0x${this.pc.toString(16)}`);
                }

                if (this.pc === 0) {
                    console.log('Program ended (PC = 0)');
                    break;
                }
            }
        } catch (error) {
            console.error(`Execution error at PC 0x${this.pc.toString(16)}:`, error.message);
            console.error(`Instruction count: ${instructionCount}`);
        }

        console.log(`Execution completed. Total instructions: ${instructionCount}`);
    }
}

function main() {
    console.log('MIPS VM starting...');

    const vm = new MipsVM();

    try {
        vm.loadELF('doomgeneric_mips');
        console.log('ELF loaded successfully');

        vm.registers[29] = 0x7FFF0000; // Stack pointer

        console.log('Starting execution...');
        vm.run();

    } catch (error) {
        console.error('VM Error:', error.message);
        process.exit(1);
    }
}

if (require.main === module) {
    main();
}
EOF
